#!/usr/bin/env bash
# Usage: ./tests/scripts/audit-fetch.sh <target1> [target2] ...
# Example: ./tests/scripts/audit-fetch.sh app components
#
# Detects direct API fetch calls including patterns:
#   fetch('/api/...')
#   fetch("/api/...")
#   fetch(`/api/...`)
#   fetch( '/api/...' )         (extra whitespace)
#   fetch(\n  '/api/...'\n)     (multi-line)
#
# Codex round 4 issue #1: original regex missed backticks + whitespace.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
DENY_FILE="$SCRIPT_DIR/scope-denylist.txt"

if ! command -v rg >/dev/null 2>&1; then
  echo "ripgrep (rg) required" >&2
  exit 2
fi

if [ "$#" -lt 1 ]; then
  echo "usage: $0 <dir1> [dir2] ..." >&2
  exit 2
fi

GLOBS=()
while IFS= read -r line; do
  [[ -z "$line" || "$line" =~ ^# ]] && continue
  GLOBS+=("--glob" "!${line}/**" "--glob" "!${line}")
done < "$DENY_FILE"

# Multiline regex covering single/double/backtick quotes and arbitrary whitespace.
# (?s) = dot matches newlines.
rg --no-heading --line-number --color never --multiline --multiline-dotall \
  "fetch\s*\(\s*[\`'\"]/api" \
  "${GLOBS[@]}" \
  --type-add 'tsx:*.tsx' --type-add 'ts:*.ts' --type tsx --type ts \
  "$@" || true
```

Make executable: `chmod +x tests/scripts/audit-fetch.sh`.

