import { handlers } from './handlers';
export const server = setupServer(...handlers);
```

- [ ] **Step 1.8.3: Opt-in enabler (replaces fetch + localStorage explicitly)**

Codex round 3 issues #1, #2, #3: `import 'whatwg-fetch'` does NOT override `global.fetch = jest.fn()` from `jest.setup.js` (the mock is already in place when import runs). Must explicitly reassign `globalThis.fetch`. Also `jest.setup.js` defines `localStorage` as plain `jest.fn()` (non-stateful) — auth tests will fail. Move ALL setup into `enable-msw.ts`; do NOT modify `jest.setup.js`.

**Plan rationale (do NOT include in `enable-msw.ts`):** The existing `jest.setup.js` declares `global.fetch = jest.fn()` before any test file loads. A bare `import 'whatwg-fetch'` won't install a real fetch on top of the existing jest mock — the polyfill's IIFE checks `typeof self.fetch !== 'function'` and bails out when the mock is already there. So `installRealFetch()` must (a) remove the existing fetch, (b) bust the require-cache for `whatwg-fetch`, (c) re-require it, (d) verify a real (non-mock) fetch is installed.

`tests/mocks/enable-msw.ts`:

```ts
import { server } from './server';

const SAVED = {
  fetch: globalThis.fetch,
  localStorage: globalThis.localStorage,
};

function installRealFetch() {
  delete (globalThis as any).fetch;
  delete (globalThis as any).Request;
  delete (globalThis as any).Response;
  delete (globalThis as any).Headers;
  // eslint-disable-next-line @typescript-eslint/no-require-imports
  delete require.cache[require.resolve('whatwg-fetch')];
  // eslint-disable-next-line @typescript-eslint/no-require-imports
  require('whatwg-fetch');
  if (typeof globalThis.fetch !== 'function' || (globalThis.fetch as any)._isMockFunction) {
    throw new Error('enable-msw: failed to install real fetch');
  }
}

function makeStatefulStorage() {
  let store: Record<string, string> = {};
  return {
    getItem: (k: string) => (k in store ? store[k] : null),
    setItem: (k: string, v: string) => {
      store[k] = String(v);
    },
    removeItem: (k: string) => {
      delete store[k];
    },
    clear: () => {
      store = {};
    },
    key: (i: number) => Object.keys(store)[i] ?? null,
    get length() {
      return Object.keys(store).length;
    },
  } satisfies Storage;
}

beforeAll(() => {
  installRealFetch();
  Object.defineProperty(globalThis, 'localStorage', {
    value: makeStatefulStorage(),
    writable: true,
    configurable: true,
  });
  server.listen({ onUnhandledRequest: 'bypass' });
});

beforeEach(() => {
  globalThis.localStorage.clear();
});

afterEach(() => server.resetHandlers());

afterAll(() => {
  server.close();
  globalThis.fetch = SAVED.fetch;
  Object.defineProperty(globalThis, 'localStorage', {
    value: SAVED.localStorage,
    writable: true,
    configurable: true,
  });
});

export { server };
```

**`jest.setup.js` is NOT modified by this plan.** All overrides happen inside `enable-msw.ts` and are scoped to test files that import it.

(MSW smoke tests consolidated into Step 1.8.5 below — single file, single source of truth. Codex round 5 issue #1.)

