## W3 Integration Test Recipe (mandatory per migrated screen — codex round 4 issue #7)

Each W3 integration test MUST cover all 5 assertions below. Shallow tests covering only initial render are NOT sufficient.

| # | Assertion | Example |
|---|---|---|
| 1 | **Initial load + render** | Mock GET; `await screen.findByText('row label')` |
| 2 | **Loading state** | Slow handler; assert spinner/skeleton appears before resolve |
| 3 | **Error state** | Handler returns 500; assert error UI/toast |
| 4 | **Filter/search refetch** | Type into search; assert second GET fires with correct query param |
| 5 | **Mutation + invalidation** | Trigger mutation (create/update/sign); assert mutation request fires; assert list refetches (second GET) |

Test file template:

```tsx
/**
 * @jest-environment jsdom
 */
import { render, screen, fireEvent, waitFor } from '@testing-library/react';
import { http, HttpResponse } from 'msw';
import { server } from 'tests/mocks/enable-msw';
import { QueryWrapper } from 'tests/utils/query-wrapper';
import Page from '../page';

jest.mock('next/navigation', () => ({
  useRouter: () => ({ push: jest.fn() }),
  usePathname: () => '/admin/<route>',
}));

describe('<RouteName>', () => {
  beforeEach(() => {
    localStorage.setItem('admin_token', 'test-token');
  });

  it('1) loads list and renders rows', async () => {
    server.use(http.get('*/api/admin/<endpoint>', () => HttpResponse.json({ /* fixture */ })));
    render(<Page />, { wrapper: QueryWrapper });
    await screen.findByText('<expected row text>');
  });

  it('2) shows loading state before resolve', async () => {
    server.use(
      http.get('*/api/admin/<endpoint>', async () => {
        await new Promise((r) => setTimeout(r, 100));
        return HttpResponse.json({ /* fixture */ });
      }),
    );
    render(<Page />, { wrapper: QueryWrapper });
    expect(screen.getByRole('status') || screen.getByText(/đang tải/i)).toBeInTheDocument();
  });

  it('3) shows error state on 500', async () => {
    server.use(
      http.get('*/api/admin/<endpoint>', () =>
        HttpResponse.json({ error: 'Server error', code: 'SERVER_ERROR' }, { status: 500 }),
      ),
    );
    render(<Page />, { wrapper: QueryWrapper });
    await waitFor(() => expect(screen.getByText(/lỗi|error/i)).toBeInTheDocument());
  });

  it('4) filter triggers refetch with query param', async () => {
    let secondCallParams: URLSearchParams | null = null;
    let callCount = 0;
    server.use(
      http.get('*/api/admin/<endpoint>', ({ request }) => {
        callCount++;
        if (callCount === 2) secondCallParams = new URL(request.url).searchParams;
        return HttpResponse.json({ /* fixture */ });
      }),
    );
    render(<Page />, { wrapper: QueryWrapper });
    await screen.findByText('<expected>');
    fireEvent.change(screen.getByPlaceholderText(/tìm kiếm/i), { target: { value: 'an' } });
    await waitFor(() => expect(secondCallParams?.get('search')).toBe('an'));
  });

  it('5) mutation triggers invalidation (list refetch)', async () => {
    let getCount = 0;
    server.use(
      http.get('*/api/admin/<endpoint>', () => {
        getCount++;
        return HttpResponse.json({ /* fixture */ });
      }),
      http.post('*/api/admin/<mutation-endpoint>', () => HttpResponse.json({ success: true })),
    );
    render(<Page />, { wrapper: QueryWrapper });
    await screen.findByText('<expected>');
    fireEvent.click(screen.getByRole('button', { name: /<action label>/i }));
    /* fill form / confirm if needed */
    await waitFor(() => expect(getCount).toBeGreaterThanOrEqual(2));
  });
});
```

