```ts
import { ApiError, ApiErrorCodes } from './errors';

const TOKEN_KEYS = ['admin_token', 'auth_token'] as const;
const USER_INFO_KEYS = ['user_info', 'admin_user', 'employee_user'] as const;

let onAuthExpired: (() => void) | null = null;
export function setOnAuthExpired(handler: () => void) {
  onAuthExpired = handler;
}

function getToken(): string | null {
  if (typeof window === 'undefined') return null;
  for (const key of TOKEN_KEYS) {
    const v = localStorage.getItem(key);
    if (v) return v;
  }
  return null;
}

function clearToken() {
  if (typeof window === 'undefined') return;
  TOKEN_KEYS.forEach(k => localStorage.removeItem(k));
  USER_INFO_KEYS.forEach(k => localStorage.removeItem(k));
}

interface RequestOpts {
  signal?: AbortSignal;
  headers?: Record<string, string>;
}

async function request<T>(
  method: string,
  path: string,
  body: unknown | undefined,
  opts: RequestOpts = {},
): Promise<T> {
  const headers = new Headers(opts.headers);
  const token = getToken();
  if (token) headers.set('Authorization', `Bearer ${token}`);
  if (body !== undefined && !(body instanceof FormData)) {
    headers.set('Content-Type', 'application/json');
  }

  let response: Response;
  try {
    response = await fetch(path, {
      method,
      headers,
      body:
        body === undefined
          ? undefined
          : body instanceof FormData
            ? body
            : JSON.stringify(body),
      signal: opts.signal,
      credentials: 'include',
    });
  } catch (err) {
    if (err instanceof DOMException && err.name === 'AbortError') throw err;
    throw new ApiError(ApiErrorCodes.NETWORK_ERROR, 'Lỗi kết nối mạng');
  }

  if (response.status === 401) {
    clearToken();
    if (onAuthExpired) onAuthExpired();
    throw new ApiError(
      ApiErrorCodes.AUTH_EXPIRED,
      'Phiên đăng nhập đã hết hạn',
      401,
    );
  }

  const text = await response.text();
  let parsed: any = null;
  if (text) {
    try {
      parsed = JSON.parse(text);
    } catch {
      parsed = text;
    }
  }

  if (!response.ok) {
    const code =
      (parsed && typeof parsed === 'object' && parsed.code) ||
      mapStatusToCode(response.status);
    const message =
      (parsed && typeof parsed === 'object' && parsed.error) ||
      `Lỗi ${response.status}`;
    const details = parsed && typeof parsed === 'object' ? parsed.details : undefined;
    throw new ApiError(code, message, response.status, details);
  }

  return parsed as T;
}

function mapStatusToCode(status: number): string {
  if (status === 400) return ApiErrorCodes.VALIDATION_ERROR;
  if (status === 403) return ApiErrorCodes.FORBIDDEN;
  if (status === 404) return ApiErrorCodes.NOT_FOUND;
  if (status === 409) return ApiErrorCodes.CONFLICT;
  if (status === 429) return ApiErrorCodes.RATE_LIMITED;
  if (status >= 500) return ApiErrorCodes.SERVER_ERROR;
  return ApiErrorCodes.UNKNOWN;
}

async function requestBlob(
  path: string,
  body: unknown | undefined,
  opts: RequestOpts = {},
  method = 'POST',
): Promise<{ blob: Blob; filename: string | null; contentType: string | null }> {
  const headers = new Headers(opts.headers);
  const token = getToken();
  if (token) headers.set('Authorization', `Bearer ${token}`);
  if (body !== undefined && !(body instanceof FormData)) {
    headers.set('Content-Type', 'application/json');
  }

  let response: Response;
  try {
    response = await fetch(path, {
      method,
      headers,
      body:
        body === undefined
          ? undefined
          : body instanceof FormData
            ? body
            : JSON.stringify(body),
      signal: opts.signal,
      credentials: 'include',
    });
  } catch (err) {
    if (err instanceof DOMException && err.name === 'AbortError') throw err;
    throw new ApiError(ApiErrorCodes.NETWORK_ERROR, 'Lỗi kết nối mạng');
  }

  if (response.status === 401) {
    clearToken();
    if (onAuthExpired) onAuthExpired();
    throw new ApiError(ApiErrorCodes.AUTH_EXPIRED, 'Phiên đăng nhập đã hết hạn', 401);
  }

  if (!response.ok) {
    const ct = response.headers.get('content-type') ?? '';
    if (ct.includes('application/json')) {
      const parsed = await response.json().catch(() => null);
      const code = parsed?.code ?? mapStatusToCode(response.status);
      const message = parsed?.error ?? `Lỗi ${response.status}`;
      throw new ApiError(code, message, response.status, parsed?.details);
    }
    throw new ApiError(mapStatusToCode(response.status), `Lỗi ${response.status}`, response.status);
  }

  const blob = await response.blob();
  const cd = response.headers.get('content-disposition');
  const match = cd?.match(/filename\*?=(?:UTF-8'')?"?([^";]+)"?/i);
  const filename = match ? decodeURIComponent(match[1]) : null;
  const contentType = response.headers.get('content-type');
  return { blob, filename, contentType };
}

export const apiClient = {
  get: <T = unknown>(path: string, opts?: RequestOpts) =>
    request<T>('GET', path, undefined, opts),
  post: <T = unknown>(path: string, body?: unknown, opts?: RequestOpts) =>
    request<T>('POST', path, body, opts),
  put: <T = unknown>(path: string, body?: unknown, opts?: RequestOpts) =>
    request<T>('PUT', path, body, opts),
  patch: <T = unknown>(path: string, body?: unknown, opts?: RequestOpts) =>
    request<T>('PATCH', path, body, opts),
  delete: <T = unknown>(path: string, opts?: RequestOpts) =>
    request<T>('DELETE', path, undefined, opts),
  blob: (path: string, body?: unknown, opts?: RequestOpts) =>
    requestBlob(path, body, opts, body !== undefined ? 'POST' : 'GET'),
};

export function downloadBlob(blob: Blob, filename: string) {
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  a.remove();
  setTimeout(() => URL.revokeObjectURL(url), 1000);
}
