```ts
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { apiClient } from '@/lib/api/client';
import { withToast } from '@/lib/api/mutation-helpers';
import { ENDPOINTS } from '@/lib/api/endpoints';

export interface Employee {
  employee_id: string;
  full_name: string;
  department: string | null;
  chuc_vu: string;
  phone_number: string | null;
  is_active: boolean;
  created_at: string;
  updated_at: string;
}

export interface EmployeesResponse {
  employees: Employee[];
  pagination: { page: number; limit: number; total: number; totalPages: number };
  departments: string[];
}

export interface EmployeesFilters {
  page?: number;
  limit?: number;
  search?: string;
  department?: string;
  role?: string;
}

export function employeesKey(filters: EmployeesFilters) {
  return ['employees', filters] as const;
}

export function useEmployeesQuery(filters: EmployeesFilters) {
  return useQuery({
    queryKey: employeesKey(filters),
    queryFn: ({ signal }) => {
      const params = new URLSearchParams();
      Object.entries(filters).forEach(([k, v]) => {
        if (v !== undefined && v !== '' && v !== null) {
          params.set(k, String(v));
        }
      });
      return apiClient.get<EmployeesResponse>(
        `${ENDPOINTS.employees.list}?${params.toString()}`,
        { signal },
      );
    },
    staleTime: 60_000,
    placeholderData: (prev) => prev,
  });
}

export function useEmployeeMutation() {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (input: {
      action: 'create' | 'update' | 'delete';
      employee: Partial<Employee> & { employee_id?: string };
    }) => {
      if (input.action === 'create') {
        return apiClient.post(ENDPOINTS.employees.create, input.employee);
      }
      const id = input.employee.employee_id!;
      if (input.action === 'update') {
        return apiClient.put(ENDPOINTS.employees.update(id), input.employee);
      }
      return apiClient.delete(ENDPOINTS.employees.delete(id));
    },
    ...withToast({
      success: 'Đã lưu thay đổi',
      onSuccess: () => {
        qc.invalidateQueries({ queryKey: ['employees'] });
        qc.invalidateQueries({ queryKey: ['departments'] });
      },
    }),
  });
}
```

(Note: actual API URL path/method may differ — verify by reading `app/api/admin/employees/route.ts` and any nested `[id]/route.ts` before implementing. Adjust calls accordingly.)

