## Task 4.1: VirtualizedTable wrapper

Codex review issue #9: original design used absolute-positioned `<TableRow>` inside semantic `<table>` markup — this breaks column alignment and screen readers. Use **div-based grid layout in virtualized mode** (TanStack Virtual recommended pattern); retain real `<table>` semantics only for the non-virtualized fallback (small lists).

**Files:**
- Create: `components/ui/virtualized-table.tsx`
- Test: `components/ui/__tests__/virtualized-table.test.tsx`

- [ ] **Step 4.1.1: Implement (div-grid layout in virtualize mode + ARIA + keyboard nav)**

```tsx
'use client';

import { useRef, useState, useEffect, type ReactNode, type CSSProperties } from 'react';
import { useVirtualizer } from '@tanstack/react-virtual';
import {
  Table,
  TableBody,
  TableHeader,
  TableRow,
  TableHead,
  TableCell,
} from '@/components/ui/table';
import { cn } from '@/lib/utils';

export interface VirtualColumn<T> {
  key: string;
  header: ReactNode;
  cell: (row: T, index: number) => ReactNode;
  /** CSS grid template (virtualized mode), e.g. "200px" | "minmax(120px,1fr)" */
  width?: string;
}

interface VirtualizedTableProps<T> {
  data: T[];
  columns: VirtualColumn<T>[];
  estimateRowHeight?: number;
  overscan?: number;
  enabledThreshold?: number;
  containerHeight?: number | string;
  rowKey: (row: T, index: number) => string;
  emptyState?: ReactNode;
  caption?: string;
  onRowFocus?: (index: number) => void;
}

export function VirtualizedTable<T>({
  data,
  columns,
  estimateRowHeight = 56,
  overscan = 8,
  enabledThreshold = 100,
  containerHeight = 600,
  rowKey,
  emptyState,
  caption,
  onRowFocus,
}: VirtualizedTableProps<T>) {
  const parentRef = useRef<HTMLDivElement>(null);
  const [focusedIdx, setFocusedIdx] = useState(0);
  const shouldVirtualize = data.length >= enabledThreshold;

  const virtualizer = useVirtualizer({
    count: data.length,
    getScrollElement: () => parentRef.current,
    estimateSize: () => estimateRowHeight,
    overscan,
  });

  useEffect(() => {
    if (shouldVirtualize) virtualizer.scrollToIndex(focusedIdx, { align: 'auto' });
  }, [focusedIdx, virtualizer, shouldVirtualize]);

  if (data.length === 0) {
    return (
      <div className="p-4 text-center text-muted-foreground" role="status">
        {emptyState ?? 'Không có dữ liệu'}
      </div>
    );
  }

  if (!shouldVirtualize) {
    return (
      <Table>
        {caption && <caption className="sr-only">{caption}</caption>}
        <TableHeader>
          <TableRow>
            {columns.map((c) => (
              <TableHead key={c.key} style={{ width: c.width }}>
                {c.header}
              </TableHead>
            ))}
          </TableRow>
        </TableHeader>
        <TableBody>
          {data.map((row, idx) => (
            <TableRow key={rowKey(row, idx)}>
              {columns.map((c) => (
                <TableCell key={c.key}>{c.cell(row, idx)}</TableCell>
              ))}
            </TableRow>
          ))}
        </TableBody>
      </Table>
    );
  }

  const gridTemplate = columns.map((c) => c.width ?? 'minmax(120px,1fr)').join(' ');
  const rowGridStyle: CSSProperties = {
    display: 'grid',
    gridTemplateColumns: gridTemplate,
    alignItems: 'center',
  };

  function handleKeyDown(e: React.KeyboardEvent) {
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      const next = Math.min(data.length - 1, focusedIdx + 1);
      setFocusedIdx(next);
      onRowFocus?.(next);
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      const next = Math.max(0, focusedIdx - 1);
      setFocusedIdx(next);
      onRowFocus?.(next);
    } else if (e.key === 'Home') {
      e.preventDefault();
      setFocusedIdx(0);
      onRowFocus?.(0);
    } else if (e.key === 'End') {
      e.preventDefault();
      const last = data.length - 1;
      setFocusedIdx(last);
      onRowFocus?.(last);
    }
  }

  return (
    <div
      ref={parentRef}
      role="grid"
      aria-rowcount={data.length}
      aria-label={caption ?? 'Bảng dữ liệu'}
      tabIndex={0}
      onKeyDown={handleKeyDown}
      style={{
        height: typeof containerHeight === 'number' ? `${containerHeight}px` : containerHeight,
        overflow: 'auto',
      }}
      className="border rounded outline-none focus-visible:ring-2 focus-visible:ring-ring"
    >
      <div
        role="row"
        style={{ ...rowGridStyle, position: 'sticky', top: 0, zIndex: 1 }}
        className="bg-background border-b font-medium text-sm"
      >
        {columns.map((c) => (
          <div key={c.key} role="columnheader" className="px-4 py-3">
            {c.header}
          </div>
        ))}
      </div>
      <div style={{ height: `${virtualizer.getTotalSize()}px`, position: 'relative' }}>
        {virtualizer.getVirtualItems().map((vRow) => {
          const row = data[vRow.index];
          const isFocused = vRow.index === focusedIdx;
          return (
            <div
              key={rowKey(row, vRow.index)}
              role="row"
              aria-rowindex={vRow.index + 1}
              aria-selected={isFocused}
              data-index={vRow.index}
              ref={(el) => virtualizer.measureElement(el)}
              style={{
                ...rowGridStyle,
                position: 'absolute',
                top: 0,
                left: 0,
                width: '100%',
                transform: `translateY(${vRow.start}px)`,
              }}
              className={cn('border-b text-sm', isFocused && 'bg-accent')}
            >
              {columns.map((c) => (
                <div key={c.key} role="gridcell" className="px-4 py-3">
                  {c.cell(row, vRow.index)}
                </div>
              ))}
            </div>
          );
        })}
      </div>
    </div>
  );
}
```

