import { render, screen, fireEvent } from '@testing-library/react';
import { VirtualizedTable, type VirtualColumn } from '../virtualized-table';

const cols: VirtualColumn<{ name: string }>[] = [
  { key: 'name', header: 'Tên', cell: (r) => r.name, width: '200px' },
];

describe('VirtualizedTable', () => {
  it('renders semantic <table> when below threshold', () => {
    const data = Array.from({ length: 50 }, (_, i) => ({ name: `r${i}` }));
    render(
      <VirtualizedTable
        data={data}
        columns={cols}
        rowKey={(_, i) => String(i)}
        enabledThreshold={100}
      />,
    );
    expect(screen.getByRole('table')).toBeInTheDocument();
  });

  it('renders role=grid when virtualized with aria-rowcount', () => {
    const data = Array.from({ length: 200 }, (_, i) => ({ name: `r${i}` }));
    render(
      <VirtualizedTable
        data={data}
        columns={cols}
        rowKey={(_, i) => String(i)}
        enabledThreshold={100}
      />,
    );
    const grid = screen.getByRole('grid');
    expect(grid).toHaveAttribute('aria-rowcount', '200');
  });

  it('exposes columnheader role in virtualized mode', () => {
    const data = Array.from({ length: 200 }, (_, i) => ({ name: `r${i}` }));
    render(
      <VirtualizedTable
        data={data}
        columns={cols}
        rowKey={(_, i) => String(i)}
        enabledThreshold={100}
      />,
    );
    expect(screen.getAllByRole('columnheader')).toHaveLength(1);
  });

  it('arrow-down moves focus and fires onRowFocus(1)', () => {
    const onFocus = jest.fn();
    const data = Array.from({ length: 200 }, (_, i) => ({ name: `r${i}` }));
    render(
      <VirtualizedTable
        data={data}
        columns={cols}
        rowKey={(_, i) => String(i)}
        enabledThreshold={100}
        onRowFocus={onFocus}
      />,
    );
    const grid = screen.getByRole('grid');
    grid.focus();
    fireEvent.keyDown(grid, { key: 'ArrowDown' });
    expect(onFocus).toHaveBeenCalledWith(1);
  });

  it('renders empty state', () => {
    render(
      <VirtualizedTable
        data={[]}
        columns={cols}
        rowKey={(_, i) => String(i)}
        emptyState="Không có dữ liệu"
      />,
    );
    expect(screen.getByText('Không có dữ liệu')).toBeInTheDocument();
  });
});
